export type Route = "discard" | "apply" | "tailored";
export type CompanyTag = "unknown" | "dream" | "blacklisted" | string;

const APPLY_THRESHOLD = 70;
const TAILORED_THRESHOLD = 80;

export function routeByScore(score: number, companyTag: CompanyTag): Route {
  if (companyTag === "blacklisted") return "discard";
  if (companyTag === "dream") return "tailored";

  if (score >= TAILORED_THRESHOLD) return "tailored";
  if (score >= APPLY_THRESHOLD) return "apply";
  return "discard";
}

import { describe, test, expect } from "bun:test";
import { routeByScore } from "./scoring";

describe("routeByScore", () => {
  test("score 69 with unknown => discard", () => {
    expect(routeByScore(69, "unknown")).toBe("discard");
  });

  test("score 70 with unknown => apply", () => {
    expect(routeByScore(70, "unknown")).toBe("apply");
  });

  test("score 79 with unknown => apply", () => {
    expect(routeByScore(79, "unknown")).toBe("apply");
  });

  test("score 80 with unknown => tailored", () => {
    expect(routeByScore(80, "unknown")).toBe("tailored");
  });

  test("score 30 with dream => tailored (dream override)", () => {
    expect(routeByScore(30, "dream")).toBe("tailored");
  });

  test("score 95 with blacklisted => discard (blacklist override)", () => {
    expect(routeByScore(95, "blacklisted")).toBe("discard");
  });
});
